const BASE_PREMIUM: Record<string, number> = {
  sword: 100,
  amulet: 60,
  staff: 80,
  potion: 40,
};

const FIRST_INSURANCE_MULTIPLIER = 1.1;
const PROCESSING_FEE = 5;

const ceilToWholeG = (amount: number): number =>
  Math.ceil(Math.round(amount * 100) / 100);

const quote = (items: Item[]): number => {
  const base = items.reduce((sum, item) => sum + (BASE_PREMIUM[item.type] ?? 0), 0);
  return ceilToWholeG(base * FIRST_INSURANCE_MULTIPLIER) + PROCESSING_FEE;
};
